import React, { useEffect, useState } from "react";

const UploadBills = ({ employee }) => {
  const [selectedFiles, setSelectedFiles] = useState([]);
  const [billData, setBillData] = useState([]);

  useEffect(() => {
    if (employee?.empId || employee?.empld) fetchBills();
  }, [employee]);

  const fetchBills = async () => {
    try {
      const empId = employee.empId || employee.empld;

      const response = await fetch(
        `https://prasa-app-yde3.onrender.com/bills?empId=${empId}`
      );

      const result = await response.json();
      setBillData(Array.isArray(result) ? result : []);
    } catch (err) {
      setBillData([]);
    }
  };

  const uploadBills = async () => {
    if (selectedFiles.length === 0) return alert("Select files first");

    const empId = employee.empId || employee.empld;
    const formData = new FormData();

    Array.from(selectedFiles).forEach((file) => {
      formData.append("files", file);
    });

    formData.append("empId", empId);

    const response = await fetch("https://prasa-app-yde3.onrender.com/upload-bills", {
      method: "POST",
      body: formData,
    });

    if (response.ok) {
      alert("Bills uploaded successfully!");
      fetchBills();
    }
  };

  const deleteBill = async (id) => {
    const response = await fetch(
      `https://prasa-app-yde3.onrender.com/delete-bill/${id}`,
      { method: "DELETE" }
    );

    if (response.ok) {
      alert("Bill deleted");
      fetchBills();
    }
  };

  const downloadReport = () => {
    alert("Bills monthly report download triggered.");
  };

  return (
    <div style={page}>
      <div style={card}>
        {/* HEADER */}
        <div style={headerRow}>
          <button style={backBtn} onClick={() => window.history.back()}>
            ←
          </button>
          <h2 style={title}>Bills Upload History</h2>
        </div>

        <p style={empInfo}>
          Employee: {employee?.empName || employee?.name} •{" "}
          {employee?.empId || employee?.empld}
        </p>

        {/* UPLOAD BOX */}
        <div style={uploadBox}>
          <input
            type="file"
            multiple
            onChange={(e) => setSelectedFiles(e.target.files)}
            style={fileInput}
          />
          <button style={uploadBtn} onClick={uploadBills}>
            Upload Bills
          </button>
        </div>

        {/* TABLE */}
        <table style={table}>
          <thead>
            <tr>
              <th>Date</th>
              <th>File Name</th>
              <th>Preview</th>
              <th>Delete</th>
            </tr>
          </thead>

          <tbody>
            {billData.length === 0 ? (
              <tr>
                <td colSpan="4" style={empty}>
                  No bills uploaded yet
                </td>
              </tr>
            ) : (
              billData.map((bill) => (
                <tr key={bill.id}>
                  <td>{bill.uploaded_at?.slice(0, 10)}</td>
                  <td>{bill.file_name}</td>
                  <td>
                    <a href={bill.file_path} target="_blank">
                      View
                    </a>
                  </td>
                  <td>
                    <button
                      onClick={() => deleteBill(bill.id)}
                      style={deleteBtn}
                    >
                      Delete
                    </button>
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>

        {/* DOWNLOAD BUTTON */}
        <div style={downloadWrap}>
          <button style={downloadBtn} onClick={downloadReport}>
            📄 Download Monthly Report
          </button>
        </div>
      </div>
    </div>
  );
};

export default UploadBills;

/* ---------------- STYLES ---------------- */

const green = "#0f9d58";

const page = {
  background: "#e8f5e9",
  minHeight: "100vh",
  padding: "30px 0",
};

const card = {
  width: "90%",
  maxWidth: "1000px",
  margin: "0 auto",
  background: "#fff",
  borderRadius: "14px",
  padding: "20px",
  boxShadow: "0 4px 12px rgba(0,0,0,0.08)",
};

const headerRow = { display: "flex", alignItems: "center", gap: 10 };

const backBtn = {
  background: "#fff",
  border: `2px solid ${green}`,
  padding: "6px 12px",
  borderRadius: 10,
  cursor: "pointer",
  color: green,
  fontSize: 18,
};

const title = { margin: 0, fontSize: 24, fontWeight: 700, color: green };

const empInfo = { marginTop: 5, fontSize: 14, color: "#555" };

const uploadBox = {
  display: "flex",
  alignItems: "center",
  gap: 15,
  marginTop: 20,
  marginBottom: 20,
};

const fileInput = { flex: 1 };

const uploadBtn = {
  background: green,
  color: "#fff",
  border: "none",
  padding: "10px 18px",
  borderRadius: 10,
  cursor: "pointer",
};

const table = { width: "100%", borderCollapse: "collapse" };

const empty = {
  textAlign: "center",
  padding: "20px 0",
  color: "#777",
};

const deleteBtn = {
  background: "red",
  color: "#fff",
  border: "none",
  padding: "8px 12px",
  borderRadius: 8,
  cursor: "pointer",
};

const downloadWrap = {
  marginTop: 20,
  textAlign: "left",
};

const downloadBtn = {
  background: green,
  color: "#fff",
  border: "none",
  padding: "12px 18px",
  borderRadius: 10,
  fontSize: 16,
  cursor: "pointer",
};
